<script>
  // Intersection Observer
  const revealEls = document.querySelectorAll('.section-eyebrow,.section-heading,.body-text,.right-item,.step-item');
  const obs = new IntersectionObserver((entries) => {
    entries.forEach(e => { if(e.isIntersecting) e.target.classList.add('visible'); });
  }, {threshold: 0.12});
  revealEls.forEach(el => obs.observe(el));

  // FAQ accordion
  document.querySelectorAll('.faq-item').forEach(item => {
    item.querySelector('.faq-q').addEventListener('click', () => {
      const isOpen = item.classList.contains('open');
      document.querySelectorAll('.faq-item').forEach(i => i.classList.remove('open'));
      if(!isOpen) item.classList.add('open');
    });
  });

  // Ember particles
  const ec = document.getElementById('embers');
  function spawnEmber() {
    if(!ec) return;
    const e = document.createElement('div');
    e.className = 'ember';
    const left = Math.random() * 100;
    const dx = (Math.random() - 0.5) * 60;
    const dur = 2.5 + Math.random() * 2.5;
    const delay = Math.random() * 3;
    const sz = 1 + Math.random() * 2;
    e.style.cssText = `left:${left}%;bottom:${Math.random()*30}%;--dx:${dx}px;animation-duration:${dur}s;animation-delay:${delay}s;background:hsl(${30+Math.random()*20},90%,60%);width:${sz}px;height:${sz}px;`;
    ec.appendChild(e);
    setTimeout(() => e.remove(), (dur+delay)*1000);
  }
  setInterval(spawnEmber, 200);
</script>

